description:
I'm doing some unusual things, so this could be not a bug. 

Workflow: 

1) Open connection to single server.
2) Wait some time. 
3) Close this connection
4) Open connection to replica set. << Here is error. 

Hard to describe, probably better to look at the code: 

NativeConnection.prototype.doOpenSet = function (fn) {
  if (!this.db) {
    var servers = []
      , ports = this.port
      , self = this

    this.host.forEach(function (host, i) {
      servers.push(new mongo.Server(host, Number(ports[i]), self.options.server));
    });

    var server = new ReplSetServers(servers, this.options.replset);
    this.db = new mongo.Db(this.name, server, this.options.db);

    this.db.on('fullsetup', function () {
      self.emit('fullsetup')
    });
  }

  this.db.open(function (err) {
    if (err) return fn(err);
    fn();
    listen(self); // Self is undefined because this.db is defined (!)
  });

  return this;
};

So, I think it's just a mistake and var self = this should be outside first if. 
But I'm not sure what is this.db. Maybe it should be removed after .disconnect() 

Thanks, and sorry for so poor bug report, my english is not very good.

